#include<bits/stdc++.h>
using namespace std;
long long dp[2001][2001][2][2];
long long a[2001][2001],r[2001],c[2001];
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&r[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&c[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            char ch;
            cin>>ch;
            a[i][j]=ch-'0';
        }
    }
    memset(dp,0x7f,sizeof(dp));
    dp[1][1][0][0]=0;
    dp[1][1][1][0]=r[1];
    dp[1][1][0][1]=c[1];
    dp[1][1][1][1]=r[1]+c[1];
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            for(long long k=0;k<=1;k++)
            {
                for(long long l=0;l<=1;l++)
                {
                    if(i!=n)
                    {
                        if((a[i][j]^k)==a[i+1][j])
                        {
                            dp[i+1][j][0][l]=min(dp[i][j][k][l],dp[i+1][j][0][l]);
                        }
                        else
                        {
                            dp[i+1][j][1][l]=min(dp[i][j][k][l]+r[i+1],dp[i+1][j][1][l]);
                        }
                    }
                    if(j!=m)
                    {
                        if((a[i][j]^l)==a[i][j+1])
                        {
                            dp[i][j+1][k][0]=min(dp[i][j][k][l],dp[i][j+1][k][0]);
                        }
                        else
                        {
                            dp[i][j+1][k][1]=min(dp[i][j][k][l]+c[j+1],dp[i][j+1][k][1]);
                        }
                    }
                }
            }
        }
    }
    long long ans=LLONG_MAX;
    for(long long i=0;i<=1;i++)
    {
        for(long long j=0;j<=1;j++)
        {
            ans=min(ans,dp[n][m][i][j]);
        }
    }
    printf("%lld",ans);
    return 0;
}
